#include <iostream>
#include <vector>
#include <cmath>
#include <memory>

using namespace std;

// Function to check if a number is prime
bool isPrime(int n) {
    if (n <= 1) return false;
    if (n <= 3) return true;
    if (n % 2 == 0 || n % 3 == 0) return false;
    for (int i = 5; i * i <= n; i += 6) {
        if (n % i == 0 || n % (i + 2) == 0) return false;
    }
    return true;
}

// Function to generate a sequence of prime numbers up to a limit
vector<int> generatePrimes(int limit) {
    vector<int> primes;
    for (int i = 2; i <= limit; ++i) {
        if (isPrime(i)) {
            primes.push_back(i);
        }
    }
    return primes;
}

// Recursive function to generate the pattern
void generatePattern(int depth, int level, const vector<int>& primes, int offset) {
    if (depth <= 0) return;

    for (int i = 0; i < level; ++i) {
        cout << " ";
    }

    for (int i = 0; i < level; ++i) {
        cout << primes[offset + i] << " ";
    }
    cout << endl;

    generatePattern(depth - 1, level + 2, primes, offset + level);
}

int main() {
    int maxDepth = 5;
    int primeLimit = 50;

    vector<int> primes = generatePrimes(primeLimit);

    if (primes.size() < (maxDepth * (maxDepth + 1)) / 2) {
        cout << "Not enough prime numbers to generate the pattern." << endl;
        return 1;
    }

    generatePattern(maxDepth, 1, primes, 0);

    return 0;
}
